\begin{frame}
\frametitle{執行摘要：突破 VLA 模型的效能瓶頸}
\begin{itemize}
  \item FASTer：區塊自迴歸解碼兼顧推論速度與動作保真度。
  \item OptimusVLA：全域先驗與記憶體機制減少函數評估次數。
  \item 動態剪枝：依操作階段調節視覺標記，降低運算延遲。
  \item 綜合效益：維持任務成功率，顯著提升效率與一致性。
\end{itemize}
\end{frame}

\begin{frame}
\frametitle{方法一：FASTer 框架與區塊自迴歸解碼}
\begin{itemize}
    \item FASTerVQ 透過 DCT 與 RVQ 實現高壓縮率時空建模。
    \item 動作專家模組採用區塊自迴歸平行生成動作標記。
    \item 維持高保真重建同時，大幅縮短推論時間。
    \item 解碼器無縫將離散標記還原為連續動作序列。
\end{itemize}
\begin{equation*}
\mathcal{L}_{\text{BAR}} = - \sum\nolimits_{j=1}^{J} \sum\nolimits_{i=1}^{B} \log p_\theta\!\big(c_{j,i} \,\big|\, C_{<j}, I_t, s_t, x\big)
\end{equation*}
\end{frame}

\begin{frame}{方法二：OptimusVLA 雙記憶體架構}
\begin{columns}
\begin{column}{0.48\textwidth}
\begin{itemize}
\item GPM 檢索任務動作先驗，取代標準高斯雜訊。
\item 縮短動作生成路徑，大幅減少函數評估次數。
\item LCM 動態編碼近期動作，確保軌跡平滑性。
\item 結合 CFM，提升模型對時間依賴之強健度。
\end{itemize}
\end{column}
\begin{column}{0.48\textwidth}
\centering
\includegraphics[width=0.85\textwidth,height=0.7\textheight,keepaspectratio]{p1-fig-002}
\end{column}
\end{columns}
\end{frame}

\begin{frame}{實驗結果：推論效率的顯著提升}
\begin{itemize}
  \item FASTer 區塊解碼速度超越傳統基準。
  \item OptimusVLA 提升 2.9 倍推論速度。
  \item ADP 框架實現 1.35 倍加速與低延遲。
  \item 加速成果證實實時控制的可行性。
\end{itemize}
\begin{center}
  \includegraphics[width=0.85\textwidth,height=0.7\textheight,keepaspectratio]{p1-fig-005}
\end{center}
\end{frame}

\begin{frame}
\frametitle{實驗結果：卓越的任務成功率與泛化能力}
\begin{itemize}
\item OptimusVLA 於 LIBERO 測試達 98.6\% 成功率。
\item ADP 使 OpenVLA 成功率相對提升 25.8\%。
\item FASTer 優化標記利用，展現跨任務泛化力。
\end{itemize}
\centering
\includegraphics[width=0.85\textwidth,height=0.7\textheight,keepaspectratio]{p1-fig-003}
\end{frame}

\begin{frame}{結論與未來展望}
  \begin{itemize}
    \item 提出分詞、生成與視覺感知的三維度 VLA 優化策略。
    \item FASTer 與 OptimusVLA 兼顧高推論速度與連續動作平滑性。
    \item ADP 證實物理動作軌跡可有效引導動態計算資源分配。
    \item 為資源受限且需即時反應的真實機器人應用奠定基礎。
  \end{itemize}
\end{frame}
